class Person {
    private String name;
    private int age;

    Person(String name, int age) {
        this.name = name;
        this.age = age;
    }

    // Override toString() — provides string representation
    @Override
    public String toString() {
        return "Person{name='" + name + "', age=" + age + "}";
    }

    // Override equals() — compares content, not reference
    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;

        Person person = (Person) obj;
        return age == person.age && name.equals(person.name);
    }

    // Override hashCode() — must be consistent with equals()
    @Override
    public int hashCode() {
        return name.hashCode() + age * 31;
    }
}

public class ObjectMethodsExample {
    public static void main(String[] args) {
        Person p1 = new Person("Alice", 25);
        Person p2 = new Person("Alice", 25);
        Person p3 = new Person("Bob", 30);

        // toString()
        System.out.println("p1: " + p1);  // Implicitly calls toString()
        System.out.println("p2: " + p2);
        System.out.println("p3: " + p3);

        // equals()
        System.out.println("--- equals() ---");
        System.out.println("p1.equals(p2): " + p1.equals(p2));
        System.out.println("p1.equals(p3): " + p1.equals(p3));
        System.out.println("p1 == p2: " + (p1 == p2));  // false — different objects

        // hashCode()
        System.out.println("--- hashCode() ---");
        System.out.println("p1 hash: " + p1.hashCode());
        System.out.println("p2 hash: " + p2.hashCode());  // Same if equals() true
        System.out.println("p3 hash: " + p3.hashCode());  // Different

        // Using in collections
        System.out.println("--- Collections ---");
        java.util.HashSet<Person> set = new java.util.HashSet<>();
        set.add(p1);
        set.add(p2);  // Won't add duplicate (equals/hashCode work!)
        set.add(p3);

        System.out.println("Set size: " + set.size());  // 2 (p1 and p3, p2 is duplicate)
        for (Person p : set) {
            System.out.println("  " + p);
        }
    }
}

